mapper.select:
SELECT coalesce(count(tb_order.id), 0) AS totalMonthlyOrder
FROM tb_order
         JOIN tb_order_detail tod ON tb_order.id = tod.order_id
WHERE extract(month FROM created_date) = #{startMonth}
  AND extract(year FROM created_date) = #{startYear}
  AND status_id = 5
  AND store_id = #{storeId}
GROUP BY date_trunc('month', created_date)
